mapper.select:
SELECT u.id, u.nick_name AS nickName, u.phone, u.avatar_url AS avatarUrl, u.auth_status AS authStatus, u.status, u.ban_reason AS banReason, u.campus_id AS campusId, c.name AS campusName, u.create_time AS createTime, u.last_login_time AS lastLoginTime FROM user u LEFT JOIN campus c ON u.campus_id = c.id
AND (u.nick_name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%'))
AND u.status = #{status}
AND u.auth_status = #{authStatus}
AND u.campus_id = #{campusId}
ORDER BY u.create_time DESC
